from typing import List, Dict, Optional


class Solution:
    def findClosestDepartment(self, nodes: List[str], queries: List[str]) -> str:
        # Build parent + type maps. ROOT is the implicit top department.
        parent: Dict[str, Optional[str]] = {"ROOT": None}
        is_department: Dict[str, bool] = {"ROOT": True}

        for line in nodes:
            kind, node_id, parent_id = line.split()
            parent[node_id] = parent_id
            is_department[node_id] = (kind == "Department")

        depth_cache: Dict[str, int] = {"ROOT": 0}

        def depth(node: str) -> int:
            # steps from node up to ROOT, memoized
            if node in depth_cache:
                return depth_cache[node]
            d = 1 + depth(parent[node])
            depth_cache[node] = d
            return d

        def lca(a: str, b: str) -> str:
            # lift the deeper node until depths match
            while depth(a) > depth(b):
                a = parent[a]
            while depth(b) > depth(a):
                b = parent[b]
            # climb together until they meet
            while a != b:
                a = parent[a]
                b = parent[b]
            return a

        # fold the LCA across all queried employees
        answer = queries[0]
        for emp in queries[1:]:
            answer = lca(answer, emp)

        # single-employee query yields an employee node -> step up to its department
        if not is_department[answer]:
            answer = parent[answer]

        return answer


def main():
    import sys
    data = sys.stdin.read().split("\n")
    idx = 0
    n = int(data[idx]); idx += 1
    nodes = []
    for _ in range(n):
        nodes.append(data[idx]); idx += 1
    queries = data[idx].split()
    print(Solution().findClosestDepartment(nodes, queries))


if __name__ == "__main__":
    main()
